1	package network
2	
3	import (
4		"errors"
5		"fmt"
6		"time"
7	)
8	
9	var (
10		// ErrInteractionNotFound reports that no current interaction matched the
11		// lifecycle message being applied.
12		ErrInteractionNotFound = errors.New("network: interaction not found")
13		// ErrInteractionActorNotAllowed reports a lifecycle actor outside the
14		// initiator/target pair.
15		ErrInteractionActorNotAllowed = errors.New("network: interaction actor not allowed")
16		// ErrInvalidStateTransition reports an impossible lifecycle transition.
17		ErrInvalidStateTransition = errors.New("network: invalid interaction state transition")
18		// ErrInteractionClosed reports a message for a terminal interaction that must
19		// be rejected instead of reopening the interaction.
20		ErrInteractionClosed = errors.New("network: interaction closed")
21	)
22	
23	// Interaction tracks one directed interaction inside one channel.
24	type Interaction struct {
25		ID        string
26		Channel   string
27		Initiator string
28		Target    string
29		State     InteractionState
30		CreatedAt time.Time
31		UpdatedAt time.Time
32	}
33	
34	// Validate reports whether the interaction carries a usable identity and state.
35	func (i Interaction) Validate() error {
36		if i.ID == "" {
37			return fmt.Errorf("%w: interaction id is required", ErrMissingField)
38		}
39		if i.Channel == "" {
40			return fmt.Errorf("%w: interaction channel is required", ErrMissingField)
41		}
42		if err := ValidateChannel(i.Channel); err != nil {
43			return fmt.Errorf("validate interaction channel: %w", err)
44		}
45		if i.Initiator == "" {
46			return fmt.Errorf("%w: interaction initiator is required", ErrMissingField)
47		}
48		if err := ValidatePeerID(i.Initiator); err != nil {
49			return fmt.Errorf("%w: interaction initiator", err)
50		}
51		if i.Target == "" {
52			return fmt.Errorf("%w: interaction target is required", ErrMissingField)
53		}
54		if err := ValidatePeerID(i.Target); err != nil {
55			return fmt.Errorf("%w: interaction target", err)
56		}
57		if err := i.State.Validate(); err != nil {
58			return fmt.Errorf("validate interaction state: %w", err)
59		}
60		return nil
61	}
62	
63	// IsTerminalState reports whether the state is terminal under the RFC.
64	func IsTerminalState(state InteractionState) bool {
65		switch state {
66		case StateCompleted, StateFailed, StateCanceled:
67			return true
68		default:
69			return false
70		}
71	}
72	
73	// IsParticipant reports whether the peer owns the interaction lifecycle.
74	func (i Interaction) IsParticipant(peerID string) bool {
75		return peerID == i.Initiator || peerID == i.Target
76	}
77	
78	func (i Interaction) counterparty(peerID string) (string, bool) {
79		switch peerID {
80		case i.Initiator:
81			return i.Target, true
82		case i.Target:
83			return i.Initiator, true
84		default:
85			return "", false
86		}
87	}
88	
89	// LifecycleAction explains how a lifecycle helper handled one message.
90	type LifecycleAction string
91	
92	const (
93		LifecycleActionOpened       LifecycleAction = "opened"
94		LifecycleActionAdvanced     LifecycleAction = "advanced"
95		LifecycleActionUnchanged    LifecycleAction = "unchanged"
96		LifecycleActionIgnored      LifecycleAction = "ignored"
97		LifecycleActionRejectDirect LifecycleAction = "reject_direct"
98	)
99	
100	// LifecycleResult is the reusable lifecycle decision surface for router code.
101	type LifecycleResult struct {
102		Interaction Interaction
103		Action      LifecycleAction
104		ReasonCode  *ReasonCode
105	}
106	
107	// OpenInteraction opens a new interaction from the first directed message.
108	func OpenInteraction(env Envelope, at time.Time) (Interaction, error) {
109		if env.Kind != KindDirect && env.Kind != KindCapability {
110			return Interaction{}, fmt.Errorf("%w: opening message kind=%q", ErrInvalidField, env.Kind)
111		}
112		if env.To == nil {
113			return Interaction{}, fmt.Errorf("%w: opening message to is required", ErrMissingField)
114		}
115		if env.InteractionID == nil {
116			return Interaction{}, fmt.Errorf("%w: opening message interaction_id is required", ErrMissingField)
117		}
118	
119		if at.IsZero() {
120			at = time.Now().UTC()
121		}
122	
123		interaction := Interaction{
124			ID:        *env.InteractionID,
125			Channel:   env.Channel,
126			Initiator: env.From,
127			Target:    *env.To,
128			State:     StateSubmitted,
129			CreatedAt: at,
130			UpdatedAt: at,
131		}
132	
133		if err := interaction.Validate(); err != nil {
134			return Interaction{}, fmt.Errorf("validate opened interaction: %w", err)
135		}
136	
137		return interaction, nil
138	}
139	
140	// ApplyInteractionEnvelope applies one validated lifecycle envelope to the
141	// current interaction state and returns the router-facing decision.
142	func ApplyInteractionEnvelope(current *Interaction, env Envelope, at time.Time) (LifecycleResult, error) {
143		at = normalizeInteractionTime(at)
144	
145		if current == nil {
146			return openInteractionResult(env, at)
147		}
148	
149		interaction, err := validateInteractionEnvelope(*current, env)
150		if err != nil {
151			return LifecycleResult{}, err
152		}
153		if result, terminal := terminalInteractionResult(interaction, env); terminal {
154			return result, nil
155		}
156	
157		return applyActiveInteractionEnvelope(interaction, env, at)
158	}
159	
160	func normalizeInteractionTime(at time.Time) time.Time {
161		if at.IsZero() {
162			return time.Now().UTC()
163		}
164		return at
165	}
166	
167	func openInteractionResult(env Envelope, at time.Time) (LifecycleResult, error) {
168		opened, err := OpenInteraction(env, at)
169		if err != nil {
170			if env.Kind != KindDirect && env.Kind != KindCapability {
171				return LifecycleResult{}, fmt.Errorf("%w: kind=%q", ErrInteractionNotFound, env.Kind)
172			}
173			return LifecycleResult{}, err
174		}
175		return LifecycleResult{
176			Interaction: opened,
177			Action:      LifecycleActionOpened,
178		}, nil
179	}
180	
181	func validateInteractionEnvelope(current Interaction, env Envelope) (Interaction, error) {
182		if err := current.Validate(); err != nil {
183			return Interaction{}, fmt.Errorf("validate current interaction: %w", err)
184		}
185		if err := validateInteractionIdentity(current, env); err != nil {
186			return Interaction{}, err
187		}
188		if !current.IsParticipant(env.From) {
189			return Interaction{}, fmt.Errorf("%w: from=%q", ErrInteractionActorNotAllowed, env.From)
190		}
191		if err := validateInteractionDirection(current, env); err != nil {
192			return Interaction{}, err
193		}
194		return current, nil
195	}
196	
197	func validateInteractionIdentity(current Interaction, env Envelope) error {
198		if env.InteractionID == nil || *env.InteractionID != current.ID {
199			return fmt.Errorf(
200				"%w: interaction_id=%v current=%q",
201				ErrInvalidField,
202				env.InteractionID,
203				current.ID,
204			)
205		}
206		if env.Channel != current.Channel {
207			return fmt.Errorf(
208				"%w: interaction channel=%q envelope channel=%q",
209				ErrInvalidField,
210				current.Channel,
211				env.Channel,
212			)
213		}
214		return nil
215	}
216	
217	func validateInteractionDirection(current Interaction, env Envelope) error {
218		if env.Kind != KindDirect && env.Kind != KindCapability {
219			return nil
220		}
221		if env.To == nil {
222			return fmt.Errorf("%w: %s to is required", ErrMissingField, env.Kind)
223		}
224	
225		expectedTarget, ok := current.counterparty(env.From)
226		if !ok || *env.To != expectedTarget {
227			return fmt.Errorf(
228				"%w: from=%q to=%q expected_to=%q",
229				ErrInteractionActorNotAllowed,
230				env.From,
231				*env.To,
232				expectedTarget,
233			)
234		}
235		return nil
236	}
237	
238	func terminalInteractionResult(interaction Interaction, env Envelope) (LifecycleResult, bool) {
239		if !IsTerminalState(interaction.State) {
240			return LifecycleResult{}, false
241		}
242	
243		switch env.Kind {
244		case KindTrace, KindReceipt:
245			return LifecycleResult{
246				Interaction: interaction,
247				Action:      LifecycleActionIgnored,
248			}, true
249		case KindDirect, KindCapability:
250			reason := ReasonCodeInteractionClosed
251			return LifecycleResult{
252				Interaction: interaction,
253				Action:      LifecycleActionRejectDirect,
254				ReasonCode:  &reason,
255			}, true
256		default:
257			return LifecycleResult{}, false
258		}
259	}
260	
261	func applyActiveInteractionEnvelope(interaction Interaction, env Envelope, at time.Time) (LifecycleResult, error) {
262		switch env.Kind {
263		case KindDirect, KindCapability:
264			return applyDirectOrCapability(interaction, at), nil
265		case KindReceipt:
266			receipt, err := decodeLifecycleBody[ReceiptBody](env, "receipt")
267			if err != nil {
268				return LifecycleResult{}, err
269			}
270			return applyReceipt(interaction, receipt, at)
271		case KindTrace:
272			trace, err := decodeLifecycleBody[TraceBody](env, "trace")
273			if err != nil {
274				return LifecycleResult{}, err
275			}
276			return applyTrace(interaction, trace, at)
277		default:
278			return LifecycleResult{}, fmt.Errorf("%w: lifecycle kind=%q", ErrInvalidField, env.Kind)
279		}
280	}
281	
282	func applyDirectOrCapability(interaction Interaction, at time.Time) LifecycleResult {
283		if interaction.State == StateNeedsInput {
284			interaction.State = StateWorking
285			interaction.UpdatedAt = at
286			return LifecycleResult{Interaction: interaction, Action: LifecycleActionAdvanced}
287		}
288		return LifecycleResult{Interaction: interaction, Action: LifecycleActionUnchanged}
289	}
290	
291	func decodeLifecycleBody[T any](env Envelope, label string) (T, error) {
292		var zero T
293	
294		body, err := env.DecodeBody()
295		if err != nil {
296			return zero, fmt.Errorf("decode %s body: %w", label, err)
297		}
298		typed, ok := body.(T)
299		if !ok {
300			return zero, fmt.Errorf("%w: expected %s body", ErrInvalidBody, label)
301		}
302		return typed, nil
303	}
304	
305	func applyReceipt(interaction Interaction, receipt ReceiptBody, at time.Time) (LifecycleResult, error) {
306		switch receipt.Status {
307		case ReceiptStatusAccepted, ReceiptStatusDuplicate, ReceiptStatusExpired, ReceiptStatusUnsupported:
308			return LifecycleResult{
309				Interaction: interaction,
310				Action:      LifecycleActionUnchanged,
311			}, nil
312		case ReceiptStatusRejected:
313			interaction.State = StateFailed
314		case ReceiptStatusCanceled:
315			interaction.State = StateCanceled
316		default:
317			return LifecycleResult{}, fmt.Errorf("%w: receipt status=%q", ErrInvalidStateTransition, receipt.Status)
318		}
319	
320		interaction.UpdatedAt = at
321		return LifecycleResult{
322			Interaction: interaction,
323			Action:      LifecycleActionAdvanced,
324		}, nil
325	}
326	
327	func applyTrace(interaction Interaction, trace TraceBody, at time.Time) (LifecycleResult, error) {
328		if !canApplyTrace(interaction.State, trace.State) {
329			return LifecycleResult{}, fmt.Errorf("%w: %s -> %s", ErrInvalidStateTransition, interaction.State, trace.State)
330		}
331	
332		updated := interaction
333		updated.State = trace.State
334		updated.UpdatedAt = at
335	
336		return LifecycleResult{
337			Interaction: updated,
338			Action:      LifecycleActionAdvanced,
339		}, nil
340	}
341	
342	func canApplyTrace(current InteractionState, next InteractionState) bool {
343		switch current {
344		case StateSubmitted:
345			return next == StateWorking || next == StateNeedsInput || next == StateCompleted || next == StateFailed ||
346				next == StateCanceled
347		case StateWorking:
348			return next == StateWorking || next == StateNeedsInput || next == StateCompleted || next == StateFailed ||
349				next == StateCanceled
350		case StateNeedsInput:
351			return next == StateWorking || next == StateNeedsInput || next == StateCompleted || next == StateFailed ||
352				next == StateCanceled
353		default:
354			return false
355		}
356	}
