427	func (r *Router) handleReceivedGreet(state receiveState) (RouteResult, error) {
428		body, err := decodeReceivedBody[GreetBody](state.envelope, "greet")
429		if err != nil {
430			return RouteResult{}, err
431		}
432		if _, _, refreshErr := r.peers.RefreshRemote(state.envelope.Channel, body.PeerCard, state.now); refreshErr != nil {
433			return RouteResult{}, refreshErr
434		}
435		return state.result, nil
436	}
