438	func (r *Router) handleReceivedCapability(ctx context.Context, state receiveState) (RouteResult, error) {
439		result, deliver, err := r.applyReceiveLifecycle(ctx, state, false)
440		if err != nil {
441			return RouteResult{}, err
442		}
443		if !deliver {
444			return result, nil
445		}
446		if state.envelope.IsDirected() {
447			if delivery, ok := deliveryFromLocalPeer(state.directedTarget, state.envelope); ok {
448				result.Deliveries = []Delivery{delivery}
449			}
450			return result, nil
451		}
452		result.Deliveries = deliveriesFromLocalPeers(r.peers.LocalPeers(state.envelope.Channel), state.envelope)
453		return result, nil
454	}
455	
456	func (r *Router) handleReceivedLifecycle(ctx context.Context, state receiveState) (RouteResult, error) {
457		result, deliver, err := r.applyReceiveLifecycle(ctx, state, true)
458		if err != nil {
459			return RouteResult{}, err
460		}
461		if deliver {
462			if delivery, ok := deliveryFromLocalPeer(state.directedTarget, state.envelope); ok {
463				result.Deliveries = []Delivery{delivery}
464			}
465		}
466		return result, nil
467	}
468	
469	func (r *Router) applyReceiveLifecycle(
470		ctx context.Context,
471		state receiveState,
472		emitRejectionReceipt bool,
473	) (RouteResult, bool, error) {
474		result := state.result
475		if state.envelope.InteractionID == nil {
476			return result, true, nil
477		}
478	
479		lifecycleResult, err := r.applyLifecycle(state.envelope, state.now)
480		switch {
481		case err == nil:
482			switch lifecycleResult.Action {
483			case LifecycleActionIgnored:
484				result.Ignored = true
485				return result, false, nil
486			case LifecycleActionRejectDirect:
487				reason := ReasonCodeInteractionClosed
488				result.Rejected = true
489				result.ReasonCode = &reason
490				if !emitRejectionReceipt {
491					return result, false, nil
492				}
493				return r.appendPublishedReceipt(
494					ctx,
495					result,
496					state.directedTarget,
497					state.envelope,
498					state.now,
499					ReceiptStatusRejected,
500					true,
501				)
502			default:
503				return result, true, nil
504			}
505		case errors.Is(err, ErrInteractionActorNotAllowed),
506			errors.Is(err, ErrInteractionNotFound):
507			result.Ignored = true
508			return result, false, nil
509		case errors.Is(err, ErrInvalidStateTransition):
510			reason := ReasonCodeInternal
511			result.Rejected = true
512			result.ReasonCode = &reason
513			return result, false, nil
514		default:
515			return RouteResult{}, false, err
516		}
517	}
518	
519	func (r *Router) appendPublishedReceipt(
520		ctx context.Context,
521		result RouteResult,
522		directedTarget LocalPeer,
523		envelope Envelope,
524		now time.Time,
525		status ReceiptStatus,
526		emit bool,
527	) (RouteResult, bool, error) {
528		if !emit {
529			return result, false, nil
530		}
531		receipt, built, err := buildDirectReceipt(directedTarget, envelope, now, status, *result.ReasonCode, nil)
532		if err != nil {
533			return RouteResult{}, false, err
534		}
535		if !built {
536			return result, false, nil
537		}
538	
539		result.Generated = append(result.Generated, receipt)
540		if err := r.publishGenerated(ctx, result.Generated); err != nil {
541			return RouteResult{}, false, err
542		}
543		return result, false, nil
544	}
