546	func decodeReceivedBody[T any](env Envelope, label string) (T, error) {
547		var zero T
548		body, err := env.DecodeBody()
549		if err != nil {
550			return zero, err
551		}
552		typed, ok := body.(T)
553		if !ok {
554			return zero, fmt.Errorf("network: unexpected %s body type %T", label, body)
555		}
556		return typed, nil
557	}
