717	func (r *Router) buildEnvelope(req SendRequest, now time.Time) (Envelope, error) {
718		if r.peers == nil {
719			return Envelope{}, fmt.Errorf("%w: peer registry is required", ErrInvalidField)
720		}
721	
722		sessionID := strings.TrimSpace(req.SessionID)
723		if sessionID == "" {
724			return Envelope{}, fmt.Errorf("%w: session is required", ErrMissingField)
725		}
726	
727		local, ok := r.peers.LocalBySession(sessionID)
728		if !ok {
729			return Envelope{}, fmt.Errorf("%w: session=%q", ErrLocalPeerNotFound, sessionID)
730		}
731	
732		channel := strings.TrimSpace(req.Channel)
733		if channel == "" {
734			return Envelope{}, fmt.Errorf("%w: channel is required", ErrMissingField)
735		}
736		if local.Channel != channel {
737			return Envelope{}, fmt.Errorf("%w: session=%q channel=%q", ErrLocalPeerNotFound, sessionID, channel)
738		}
739	
740		id := normalizeOptionalIdentifier(req.ID)
741		if id == nil {
742			id = ptrString(store.NewID("msg"))
743		}
744		envelope := Envelope{
745			Protocol:      ProtocolV0,
746			ID:            *id,
747			Kind:          Kind(strings.TrimSpace(string(req.Kind))),
748			Channel:       channel,
749			From:          local.PeerID,
750			To:            normalizeOptionalIdentifier(req.To),
751			InteractionID: normalizeOptionalIdentifier(req.InteractionID),
752			ReplyTo:       normalizeOptionalIdentifier(req.ReplyTo),
753			TraceID:       normalizeOptionalIdentifier(req.TraceID),
754			CausationID:   normalizeOptionalIdentifier(req.CausationID),
755			TS:            now.Unix(),
756			ExpiresAt:     cloneInt64Ptr(req.ExpiresAt),
757			Body:          cloneRawMessage(req.Body),
758			Ext:           cloneExtensionMap(req.Ext),
759		}
760	
761		if err := ValidateEnvelope(envelope, ValidateOptions{Now: now, MaxReplayAge: r.maxReplayAge}); err != nil {
762			return Envelope{}, err
763		}
764		return envelope, nil
765	}
