767	func (r *Router) resolveDirectedTarget(envelope Envelope) (LocalPeer, bool, error) {
768		if !envelope.IsDirected() {
769			return LocalPeer{}, false, nil
770		}
771		if r.peers == nil {
772			return LocalPeer{}, false, fmt.Errorf("%w: peer registry is required", ErrInvalidField)
773		}
774	
775		local, ok := r.peers.LocalByPeer(envelope.Channel, *envelope.To)
776		if !ok {
777			return LocalPeer{}, false, nil
778		}
779		return local, true, nil
780	}
