871	func (r *Router) shouldSyncSentLifecycle(envelope Envelope) bool {
872		if r == nil || r.peers == nil || !envelope.IsDirected() {
873			return true
874		}
875	
876		switch envelope.Kind {
877		case KindReceipt, KindTrace:
878			_, ok := r.peers.LocalByPeer(envelope.Channel, *envelope.To)
879			return !ok
880		default:
881			return true
882		}
883	}
