952	func deliveriesFromLocalPeers(peers []LocalPeer, envelope Envelope) []Delivery {
953		if len(peers) == 0 {
954			return nil
955		}
956	
957		deliveries := make([]Delivery, 0, len(peers))
958		for _, peer := range peers {
959			delivery, ok := deliveryFromLocalPeer(peer, envelope)
960			if !ok {
961				continue
962			}
963			deliveries = append(deliveries, delivery)
964		}
965		return deliveries
966	}
