968	func deliveryFromLocalPeer(peer LocalPeer, envelope Envelope) (Delivery, bool) {
969		if strings.TrimSpace(peer.PeerID) == "" || isEnvelopeSender(peer, envelope) {
970			return Delivery{}, false
971		}
972		return Delivery{
973			SessionID: peer.SessionID,
974			PeerID:    peer.PeerID,
975			Envelope:  envelope,
976		}, true
977	}
