979	func isEnvelopeSender(peer LocalPeer, envelope Envelope) bool {
980		return strings.TrimSpace(peer.PeerID) != "" &&
981			strings.TrimSpace(peer.PeerID) == strings.TrimSpace(envelope.From)
982	}
