482	// networkChannelAggregates merges live peers with persisted channel/session/message state for one projection pass.
483	func networkChannelAggregates(
484		ctx context.Context,
485		service NetworkService,
486		sessionsManager SessionManager,
487		networkStore NetworkStore,
488	) (map[string]*networkChannelAggregate, error) {
489		if service == nil {
490			return nil, errors.New("api: network service is required")
491		}
492		if networkStore == nil {
493			return nil, errors.New("api: network store is required")
494		}
495		if sessionsManager == nil {
496			return nil, errors.New("api: sessions are required")
497		}
498		runtimePeers, err := service.ListPeers(ctx, "")
499		if err != nil {
500			return nil, fmt.Errorf("api: list network peers: %w", err)
501		}
502		sessions, err := sessionsManager.ListAll(ctx)
503		if err != nil {
504			return nil, fmt.Errorf("api: list sessions: %w", err)
505		}
506		channelMetadata, err := networkStore.ListNetworkChannels(ctx, store.NetworkChannelQuery{})
507		if err != nil {
508			return nil, fmt.Errorf("api: list network channels: %w", err)
509		}
510		messages, err := networkStore.ListNetworkMessages(ctx, store.NetworkMessageQuery{})
511		if err != nil {
512			return nil, fmt.Errorf("api: list network messages: %w", err)
513		}
514	
515		aggregates := make(map[string]*networkChannelAggregate)
516		applyNetworkChannelMetadata(aggregates, channelMetadata)
517		applyNetworkChannelSessions(aggregates, sessions)
518		applyNetworkChannelPeers(aggregates, runtimePeers)
519		applyNetworkChannelMessages(aggregates, messages)
520		return aggregates, nil
521	}
