752	func (h *BaseHandlers) networkChannelDetailPayload(
753		ctx context.Context,
754		service NetworkService,
755		channel string,
756	) (contract.NetworkChannelDetailPayload, error) {
757		networkStore, err := h.networkStoreRequired()
758		if err != nil {
759			return contract.NetworkChannelDetailPayload{}, err
760		}
761		peers, err := service.ListPeers(ctx, channel)
762		if err != nil {
763			return contract.NetworkChannelDetailPayload{}, err
764		}
765		sessions, err := h.Sessions.ListAll(ctx)
766		if err != nil {
767			return contract.NetworkChannelDetailPayload{}, err
768		}
769	
770		filteredSessions := sessionsForChannel(sessions, channel)
771		metadata, err := h.loadNetworkChannelMetadata(ctx, networkStore, channel)
772		if err != nil {
773			return contract.NetworkChannelDetailPayload{}, err
774		}
775		messages, err := networkStore.ListNetworkMessages(ctx, store.NetworkMessageQuery{Channel: channel})
776		if err != nil {
777			return contract.NetworkChannelDetailPayload{}, err
778		}
779		history := summarizeNetworkMessageHistory(filterPublicChannelTimelineMessages(messages), h.networkPresenceWindow())
780		messageCount := len(history.conversation)
781		if len(filteredSessions) == 0 && len(peers) == 0 && len(messages) == 0 && metadata == nil {
782			return contract.NetworkChannelDetailPayload{}, fmt.Errorf("%w: %s", errNetworkChannelNotFound, channel)
783		}
784	
785		sessionByID := sessionInfoMapByID(filteredSessions)
786		payloadPeers := make([]contract.NetworkPeerPayload, 0, len(peers))
787		localPeerCount := 0
788		for _, peer := range peers {
789			if peer.Local {
790				localPeerCount++
791			}
792			payloadPeers = append(payloadPeers, networkPeerPayloadFromInfoWithSessions(peer, sessionByID))
793		}
794		sortNetworkPeerPayloads(payloadPeers)
795	
796		metadataFields := networkChannelMetadataPayloadFields(metadata)
797		var (
798			lastActivityAt     *time.Time
799			lastPresenceAt     *time.Time
800			lastMessagePreview string
801		)
802		kindCounts := summarizeNetworkChannelKindCounts(history.conversation)
803		if messageCount > 0 {
804			lastActivityAt = laterTimePtr(lastActivityAt, history.conversation[messageCount-1].Timestamp)
805			lastMessagePreview = networkMessagePreview(history.conversation[messageCount-1])
806		}
807		lastPresenceAt = cloneTimePtr(history.lastPresenceAt)
808	
809		return contract.NetworkChannelDetailPayload{
810			Channel:                    channel,
811			WorkspaceID:                metadataFields.workspaceID,
812			Purpose:                    metadataFields.purpose,
813			CreatedBy:                  metadataFields.createdBy,
814			CreatedAt:                  metadataFields.createdAt,
815			PeerCount:                  len(peers),
816			LocalPeerCount:             localPeerCount,
817			RemotePeerCount:            len(peers) - localPeerCount,
818			SessionCount:               len(filteredSessions),
819			MessageCount:               messageCount,
820			PresenceCount:              history.presenceCount,
821			HistoricalParticipantCount: summarizeHistoricalParticipantCount(messages),
822			LastActivityAt:             cloneTimePtr(lastActivityAt),
823			LastPresenceAt:             lastPresenceAt,
824			LastMessagePreview:         lastMessagePreview,
825			KindCounts:                 kindCounts,
826			Sessions:                   SessionPayloadsFromInfos(filteredSessions),
827			Peers:                      payloadPeers,
828		}, nil
829	}
