1174	func summarizeNetworkMessageHistory(
1175		messages []store.NetworkMessageEntry,
1176		presenceWindow time.Duration,
1177	) networkMessageHistorySummary {
1178		summary := networkMessageHistorySummary{
1179			conversation:     make([]store.NetworkMessageEntry, 0, len(messages)),
1180			presenceEpisodes: make([]networkTimelineMessageView, 0),
1181		}
1182		if len(messages) == 0 {
1183			return summary
1184		}
1185	
1186		participants := make(map[string]struct{})
1187		openEpisodes := make(map[networkPresenceEpisodeKey]int)
1188	
1189		for _, message := range messages {
1190			recordHistoricalParticipant(participants, message.PeerFrom)
1191			recordHistoricalParticipant(participants, message.PeerTo)
1192			if isPresenceMessage(message) {
1193				summary.presenceCount++
1194				summary.lastPresenceAt = laterTimePtr(summary.lastPresenceAt, message.Timestamp)
1195				key := networkPresenceEpisodeKeyForMessage(message)
1196				if index, ok := openEpisodes[key]; ok &&
1197					canExtendPresenceEpisode(summary.presenceEpisodes[index], message, presenceWindow) {
1198					extendPresenceEpisode(&summary.presenceEpisodes[index], message)
1199					continue
1200				}
1201				currentEpisode := networkTimelineMessageView{
1202					entry: cloneNetworkMessageEntry(message),
1203				}
1204				startedAt := message.Timestamp.UTC()
1205				lastSeenAt := message.Timestamp.UTC()
1206				currentEpisode.presenceCount = 1
1207				currentEpisode.presenceStartedAt = &startedAt
1208				currentEpisode.presenceLastSeenAt = &lastSeenAt
1209				currentEpisode.entry.PreviewText = networkMessagePreview(currentEpisode.entry)
1210				summary.presenceEpisodes = append(summary.presenceEpisodes, currentEpisode)
1211				openEpisodes[key] = len(summary.presenceEpisodes) - 1
1212				continue
1213			}
1214	
1215			summary.conversation = append(summary.conversation, cloneNetworkMessageEntry(message))
1216		}
1217		summary.historicalParticipantCount = len(participants)
1218		return summary
1219	}
