1461	func paginateNetworkTimelineViews(
1462		views []networkTimelineMessageView,
1463		query store.NetworkMessageQuery,
1464	) ([]networkTimelineMessageView, error) {
1465		paginated := views
1466		if before := strings.TrimSpace(query.BeforeMessageID); before != "" {
1467			index := indexNetworkTimelineViewByMessageID(paginated, before)
1468			if index < 0 {
1469				return nil, fmt.Errorf("network timeline before cursor: %w", sql.ErrNoRows)
1470			}
1471			paginated = paginated[:index]
1472		}
1473		if after := strings.TrimSpace(query.AfterMessageID); after != "" {
1474			index := indexNetworkTimelineViewByMessageID(paginated, after)
1475			if index < 0 {
1476				return nil, fmt.Errorf("network timeline after cursor: %w", sql.ErrNoRows)
1477			}
1478			paginated = paginated[index+1:]
1479		}
1480		if query.Limit <= 0 || len(paginated) <= query.Limit {
1481			return paginated, nil
1482		}
1483		if strings.TrimSpace(query.BeforeMessageID) != "" {
1484			return paginated[len(paginated)-query.Limit:], nil
1485		}
1486		return paginated[:query.Limit], nil
1487	}
