217	func (c *deliveryCoordinator) acceptOne(ctx context.Context, delivery Delivery) error {
218		if ctx == nil {
219			return errors.New("network: accept context is required")
220		}
221		if c == nil {
222			return errors.New("network: delivery coordinator is required")
223		}
224		if err := ctx.Err(); err != nil {
225			return err
226		}
227	
228		sessionID := strings.TrimSpace(delivery.SessionID)
229		if sessionID == "" {
230			return fmt.Errorf("%w: delivery session id is required", ErrMissingField)
231		}
232	
233		queue := c.queueForSession(sessionID)
234		result := queue.enqueue(delivery.Envelope, c.now(), c.prompter.IsPrompting(sessionID))
235		if result.Dropped != nil {
236			c.logger.Warn(
237				"network.message.queue_overflow",
238				"session_id", sessionID,
239				"dropped_envelope_id", result.Dropped.ID,
240				"queue_depth", result.Depth,
241			)
242			if c.onDropped != nil {
243				c.onDropped(sessionID, cloneEnvelope(*result.Dropped), deliveryDropReasonQueueFull)
244			}
245		}
246		if result.DeliveryMode == "queued" {
247			c.logger.Info(
248				"network.message.queued",
249				"session_id", sessionID,
250				"message_id", delivery.Envelope.ID,
251				"kind", string(delivery.Envelope.Kind),
252				"channel", delivery.Envelope.Channel,
253				"queue_depth", result.Depth,
254			)
255		}
256		c.notifyWaiters(sessionID)
257	
258		if !c.prompter.IsPrompting(sessionID) {
259			c.trigger(sessionID)
260		}
261		return nil
262	}
