443	func (c *deliveryCoordinator) trigger(sessionID string) {
444		if c == nil {
445			return
446		}
447		if err := c.lifecycleCtx.Err(); err != nil {
448			return
449		}
450		if c.queueDepth(sessionID) == 0 {
451			return
452		}
453	
454		state := &deliveryState{done: make(chan struct{})}
455		if _, loaded := c.deliveries.LoadOrStore(sessionID, state); loaded {
456			return
457		}
458	
459		c.wg.Add(1)
460		go c.runWorker(sessionID, state)
