463	func (c *deliveryCoordinator) runWorker(sessionID string, state *deliveryState) {
464		defer c.wg.Done()
465		defer close(state.done)
466		defer c.deliveries.Delete(sessionID)
467	
468		target := strings.TrimSpace(sessionID)
469		for {
470			if err := c.lifecycleCtx.Err(); err != nil {
471				return
472			}
473			if c.prompter.IsPrompting(target) {
474				return
475			}
476	
477			item, ok := c.dequeue(target)
478			if !ok {
479				return
480			}
481			if !c.processQueuedItem(target, item, state) {
482				return
483			}
484		}
485	}
