487	func (c *deliveryCoordinator) processQueuedItem(sessionID string, item queuedEnvelope, state *deliveryState) bool {
488		c.markInFlight(sessionID, item)
489		envelope := item.Envelope
490	
491		message, err := formatNetworkMessage(envelope)
492		if err != nil {
493			c.handleRenderFailure(sessionID, item, state, err)
494			return false
495		}
496	
497		events, err := c.prompter.PromptNetwork(c.lifecycleCtx, sessionID, message, promptNetworkMeta(envelope))
498		if err != nil {
499			c.handleDeliveryFailure(sessionID, item, state, err)
500			return false
501		}
502		if !c.drainPromptEvents(events) {
503			c.handleInterruptedDelivery(sessionID, item)
504			return false
505		}
506	
507		c.finishDeliveredMessage(sessionID, item)
508		return true
509	}
