522			meta.InteractionID = strings.TrimSpace(*envelope.InteractionID)
523		}
524		if envelope.ReplyTo != nil {
525			meta.ReplyTo = strings.TrimSpace(*envelope.ReplyTo)
526		}
527		if envelope.TraceID != nil {
528			meta.TraceID = strings.TrimSpace(*envelope.TraceID)
529		}
530		if envelope.CausationID != nil {
531			meta.CausationID = strings.TrimSpace(*envelope.CausationID)
532		}
533		return meta.Normalize()
534	}
