645	func (c *deliveryCoordinator) retryAfterWorkerExit(sessionID string, item queuedEnvelope, state *deliveryState) {
646		if c == nil || state == nil {
647			return
648		}
649	
650		target := strings.TrimSpace(sessionID)
651		if target == "" {
652			return
653		}
654	
655		delay := c.retryDelayFor(item.RetryAttempt)
656		c.wg.Go(func() {
657			select {
658			case <-state.done:
659			case <-c.lifecycleCtx.Done():
660				return
661			}
662	
663			c.scheduleRetry(c.lifecycleCtx, delay, func() {
664				if err := c.lifecycleCtx.Err(); err != nil {
665					return
666				}
667				if c.prompter.IsPrompting(target) {
668					return
669				}
670				if c.queueDepth(target) == 0 {
671					return
672				}
673				c.trigger(target)
674			})
675		})
676	}
