678	func (c *deliveryCoordinator) retryDelayFor(attempt int) time.Duration {
679		if c == nil {
680			return defaultDeliveryRetryBaseDelay
681		}
682		delay := c.retryBaseDelay
683		for i := 1; i < attempt; i++ {
684			if delay >= c.retryMaxDelay/2 {
685				return c.retryMaxDelay
686			}
687			delay *= 2
688		}
689		if delay > c.retryMaxDelay {
690			return c.retryMaxDelay
691		}
692		return delay
693	}
694	
695	func scheduleDeliveryRetry(ctx context.Context, delay time.Duration, fn func()) {
696		if fn == nil {
697			return
698		}
699		if delay <= 0 {
700			select {
701			case <-ctx.Done():
702				return
703			default:
704				fn()
705				return
706			}
707		}
708	
709		timer := time.NewTimer(delay)
710		defer timer.Stop()
711	
712		select {
713		case <-ctx.Done():
714			return
715		case <-timer.C:
716			fn()
717		}
718	}
