720	func (c *deliveryCoordinator) stats() deliveryCoordinatorStats {
721		if c == nil {
722			return deliveryCoordinatorStats{}
723		}
724	
725		c.mu.Lock()
726		queues := make([]*inboundQueue, 0, len(c.queues))
727		for _, queue := range c.queues {
728			queues = append(queues, queue)
729		}
730		inFlightMessages := len(c.inFlight)
731		c.mu.Unlock()
732	
733		stats := deliveryCoordinatorStats{
734			InFlightMessages: inFlightMessages,
735		}
736		for _, queue := range queues {
737			depth := queue.len()
738			if depth <= 0 {
739				continue
740			}
741			stats.QueuedMessages += depth
742			stats.QueuedSessions++
743		}
744		c.deliveries.Range(func(_, _ any) bool {
745			stats.DeliveryWorkers++
746			return true
747		})
748		return stats
749	}
