775	func (q *inboundQueue) enqueue(envelope Envelope, acceptedAt time.Time, prompting bool) enqueueResult {
776		q.mu.Lock()
777		defer q.mu.Unlock()
778	
779		var dropped *Envelope
780		wasEmpty := len(q.items) == 0
781		if len(q.items) >= q.maxDepth {
782			evicted := cloneEnvelope(q.items[0].Envelope)
783			dropped = &evicted
784			copy(q.items[0:], q.items[1:])
785			q.items = q.items[:len(q.items)-1]
786		}
787		deliveryMode := "queued"
788		if !prompting && wasEmpty {
789			deliveryMode = "immediate"
790		}
791		q.items = append(q.items, queuedEnvelope{
792			Envelope:     cloneEnvelope(envelope),
793			AcceptedAt:   acceptedAt.UTC(),
794			DeliveryMode: deliveryMode,
795		})
796	
797		return enqueueResult{
798			Depth:        len(q.items),
799			DeliveryMode: deliveryMode,
800			Dropped:      dropped,
801		}
802	}
