852	func formatNetworkMessage(envelope Envelope) (string, error) {
853		body, err := envelope.DecodeBody()
854		preview := ""
855	
856		var canonicalBody []byte
857		switch {
858		case err == nil:
859			canonicalBody, err = json.Marshal(body)
860			if err != nil {
861				return "", fmt.Errorf("network: marshal canonical body for delivery: %w", err)
862			}
863			preview = previewForBody(body)
864		case !json.Valid(envelope.Body):
865			return "", fmt.Errorf("network: decode envelope body for delivery: %w", err)
866		default:
867			var compact bytes.Buffer
868			if compactErr := json.Compact(&compact, envelope.Body); compactErr != nil {
869				return "", fmt.Errorf("network: compact raw envelope body for delivery: %w", compactErr)
870			}
871			canonicalBody = compact.Bytes()
872		}
873		encodedBody := base64.StdEncoding.EncodeToString(canonicalBody)
874	
875		var builder strings.Builder
876		builder.Grow(base64.StdEncoding.EncodedLen(len(canonicalBody)) + len(preview)*6 + 2048)
877		builder.WriteString("<network-message")
878		writeXMLAttr(&builder, "id", envelope.ID)
879		writeXMLAttr(&builder, "from", envelope.From)
880		writeXMLAttr(&builder, "channel", envelope.Channel)
881		writeXMLAttr(&builder, "kind", string(envelope.Kind))
882		if envelope.To != nil {
883			writeXMLAttr(&builder, "to", *envelope.To)
884		}
885		if envelope.InteractionID != nil {
886			writeXMLAttr(&builder, "interaction", *envelope.InteractionID)
887		}
888		if envelope.ReplyTo != nil {
889			writeXMLAttr(&builder, "reply-to", *envelope.ReplyTo)
890		}
891		if envelope.TraceID != nil {
892			writeXMLAttr(&builder, "trace-id", *envelope.TraceID)
893		}
894		if envelope.CausationID != nil {
895			writeXMLAttr(&builder, "causation-id", *envelope.CausationID)
896		}
897		if envelope.ExpiresAt != nil {
898			writeXMLAttr(&builder, "expires-at", strconv.FormatInt(*envelope.ExpiresAt, 10))
899		}
900		writeXMLAttr(&builder, "trust", "untrusted")
901		builder.WriteString(">\n")
902		if preview != "" {
903			builder.WriteString("  <network-preview encoding=\"xml-escaped\">")
904			builder.WriteString(xmlEscape(preview))
905			builder.WriteString("</network-preview>\n")
906		}
907		builder.WriteString("  <network-body encoding=\"base64-json\">")
908		builder.WriteString(encodedBody)
909		builder.WriteString("</network-body>\n")
910		builder.WriteString("</network-message>")
911		writeReplyGuidance(&builder, envelope)
912	
913		return builder.String(), nil
914	}
915	
916	func writeReplyGuidance(builder *strings.Builder, envelope Envelope) {
917		if builder == nil {
918			return
919		}
920	
921		ctx := newReplyGuidanceContext(envelope)
922		builder.WriteString("\n\n")
923		writeGuidanceLine(builder, "Use `agh network send` to respond through the audited CLI path.")
924		writeGuidanceLine(builder, ctx.replyFlagsLine())
925		writeGuidanceLine(builder, ctx.causationLine())
926	
927		if traceLine := ctx.traceLine(); traceLine != "" {
928			writeGuidanceLine(builder, traceLine)
929		}
930		if interactionLine := ctx.broadcastInteractionLine(); interactionLine != "" {
931			writeGuidanceLine(builder, interactionLine)
932		}
933		for _, line := range protocolGuidanceText {
934			writeGuidanceLine(builder, line)
935		}
936		if sayLine := ctx.sayLifecycleLine(); sayLine != "" {
937			writeGuidanceLine(builder, sayLine)
938		}
939	
940		writeGuidanceLine(builder, "Examples:")
941		writeGuidanceLine(builder, "```bash")
942		ctx.writeDirectReplyExample(builder)
943		if ctx.reuseInteraction {
944			ctx.writeProtocolReceiptExample(builder)
945			ctx.writeProtocolTraceExample(builder)
946			ctx.writeProtocolCapabilityExample(builder)
947		}
948		writeGuidanceLine(builder, "```")
949		builder.WriteString("See `agh network --help` for options.")
950	}
